import firebase_admin
from firebase_admin import credentials, firestore
from flask import Flask, request, jsonify
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

cred = credentials.Certificate("path/to/serviceAccountKey.json")
firebase_admin.initialize_app(cred)
db = firestore.client()

@app.route('/webhook', methods=['POST'])
def webhook():
    try:
        data = request.get_json()
        
        # Validate incoming data
        required_fields = ['partner_id', 'transaction_id']
        for field in required_fields:
            if field not in data:
                return jsonify({'error': f'Missing required field: {field}'}), 400
        
        # Process the event
        process_event(data)
        
        return jsonify({'message': 'Event processed successfully'}), 200
    
    except Exception as e:
        print(f'Error processing webhook event: {e}')
        return jsonify({'error': str(e)}), 500

def process_event(event):
    partner_id = event['partner_id']
    transaction_id = event['transaction_id']
    
    # Update partner's transactions in Firestore
    db.collection('partners').document(partner_id).collection('transactions').document(transaction_id).set({
        'status': 'processed'
    })

if __name__ == '__main__':
    app.run(debug=True, port=8080, host='0.0.0.0', allow_unauthenticated=True)